  formatDob(dob) {
    let value:string = dob.value;
    console.log("orginal:" + value)
    if (value.length < 6) return;
    value = value.replace(/\s|-/g, ""); // remove all spaces and '-'
    // assign back the cleaned text
    //dob.value = value; 

    //replace - with / if there are any
    //value = value.replace(/-/g, '/');    

    let parts = value.split("/");
    if (parts.length !== 3) { // all digits, no seperator
      parts[0] = value.substr(0, 2); //MM
      parts[1] = value.substr(2, 2); //DD
      parts[2] = value.substr(4); //YY or YYYY
    }

    let m = parseInt(parts[0]);
    let d = parseInt(parts[1]);
    let y = parseInt(parts[2]);

    if (y < 100) {
      if (y >= 30)
        y += 1900;
      // else 
      //   y+=2000;
      parts[2] = y + "";
    }
    
    if ((y <= 2100 && y >= 1900) &&
        (m > 0 && m < 13) &&
        (d > 0 && d < 32) ) {          
        //dob.value = parts.join('/');    
        dob.value = parts[0].padStart(2, "0") + "/" + parts[1].padStart(2, "0") + "/" + parts[2];
    } else {
      dob.value += " ";
    }
  }

